<?php $mods=[]; foreach($permisos as $p) $mods[$p['modulo']][]=$p['permiso']; ?>
<div class="card-dark"><h5><?= $item?'Editar':'Nuevo' ?> rol y accesos</h5><form method="post" action="<?= url('roles/guardar') ?>" class="row g-2"><?= csrf_field() ?><input type="hidden" name="id" value="<?= e($item['id']??'') ?>"><div class="col-md-6"><label>Nombre del rol</label><input required class="form-control" name="nombre" value="<?= e($item['nombre']??'') ?>"></div><div class="col-md-3"><label>Estado</label><select class="form-select" name="estado"><?php foreach(['activo','inactivo'] as $e): ?><option <?= ($item['estado']??'activo')===$e?'selected':'' ?>><?= $e ?></option><?php endforeach; ?></select></div><div class="col-12"><h6 class="mt-3">Permisos</h6><div class="row g-2"><?php foreach($mods as $mod=>$acciones): ?><div class="col-lg-4 col-md-6"><div class="panel h-100"><strong><?= e($mod) ?></strong><div class="mt-2"><?php foreach($acciones as $perm): ?><label class="check"><input type="checkbox" name="permisos[<?= e($mod) ?>][<?= e($perm) ?>]" value="1" <?= (!$item||!empty($activos[$mod][$perm]))?'checked':'' ?>> <?= e($perm) ?></label><?php endforeach; ?></div></div></div><?php endforeach; ?></div></div><div class="col-12 d-flex gap-2 mt-3"><button class="btn btn-seim">Guardar rol</button><a class="btn btn-outline-light" href="<?= url('roles') ?>">Cancelar</a></div></form></div>
